from flask import Flask, session, request, jsonify
import redis
from functools import wraps
import time

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Connect to Redis
redis_client = redis.Redis(host='localhost', port=6379, db=0)

# Session management with Redis
@app.before_request
def load_session():
    session_id = request.cookies.get('session_id')
    if session_id:
        session_data = redis_client.get(session_id)
        if session_data:
            # Using session data
            session.clear()
            session.update(eval(session_data))

@app.after_request
def save_session(response):
    session_id = request.cookies.get('session_id')
    if not session_id:
        session_id = str(time.time())
        response.set_cookie('session_id', session_id)
    redis_client.set(session_id, dict(session))
    return response

# Caching decorator
def cache(expiry=30):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = f'{func.__name__}:{args}:{kwargs}'
            cached_result = redis_client.get(cache_key)
            if cached_result:
                return eval(cached_result)
            result = func(*args, **kwargs)
            redis_client.setex(cache_key, expiry, result)
            return result
        return wrapper
    return decorator

@cache(expiry=60)
def expensive_db_query(param):
    time.sleep(2)  # Simulate expensive operation
    return {"result": f"Data for {param}"}

@app.route('/data/<param>')
def get_data(param):
    data = expensive_db_query(param)
    return jsonify(data)

